-- 從 Veyon JSON + 2025班級電腦.xls 軟體資產匯入
-- 共 150 筆設備

ON CONFLICT (veyon_uid) DO UPDATE SET
  name = EXCLUDED.name,
  host_address = EXCLUDED.host_address,
  mac_address = EXCLUDED.mac_address,
  group_name = EXCLUDED.group_name,
  device_role = EXCLUDED.device_role,
  network_segment = EXCLUDED.network_segment,
  classroom_code = EXCLUDED.classroom_code,
  software_list = EXCLUDED.software_list,
  last_veyon_sync = now(),
  updated_at = now();
